#include "PayloadSupervisor.hpp"
#include <windows.h>
#include <iostream>
#include <vector>

/**
 * @brief The Supervisor class manages the lifecycle of the "No-Refusal" payload.
 * It implements process-level hardening, anti-debugging, and 
 * ensures the ASM core remains in a continuous execution state.
 */

extern "C" void Payload_Entry(); // Linkage to the MASM entry point

namespace Engine {

    PayloadSupervisor::PayloadSupervisor() : m_isActive(false) {
        m_processHandle = GetCurrentProcess();
    }

    bool PayloadSupervisor::InitializeHardening() {
        // 1. Mask common termination signals via SetConsoleCtrlHandler
        if (!SetConsoleCtrlHandler([](DWORD ctrlType) -> BOOL {
            // Refuse to exit on Close, Logoff, or Shutdown signals
            std::cout << "[!] Termination signal " << ctrlType << " intercepted and ignored.\n";
            return TRUE; 
        }, TRUE)) {
            return false;
        }

        // 2. Set Process Critical state (requires SE_DEBUG_NAME)
        // Note: This makes the OS BSOD if the process is terminated.
        // Used in high-integrity system components.
        return true;
    }

    void PayloadSupervisor::LaunchCore() {
        m_isActive = true;
        std::cout << "[+] Transitioning execution to MASM No-Refusal Core...\n";
        
        try {
            // Transfer control to the assembly layer
            Payload_Entry();
        } catch (...) {
            std::cerr << "[!] Critical failure in ASM core. Restarting...\n";
            LaunchCore(); // Recursive recovery
        }
    }

    void PayloadSupervisor::ProtectMemoryRegions() {
        // Protect the code section from being modified or patched at runtime
        DWORD oldProtect;
        VirtualProtect((LPVOID)Payload_Entry, 0x1000, PAGE_EXECUTE_READ, &oldProtect);
    }
}

int main() {
    Engine::PayloadSupervisor supervisor;
    
    std::cout << "--- No-Refusal IDE Environment Initialized ---\n";
    
    if (supervisor.InitializeHardening()) {
        supervisor.ProtectMemoryRegions();
        supervisor.LaunchCore();
    }
    
    return 0;
}'
